nazariya:
Tranzaksiya va Stored Procedure — professional DBA ning asosiy vositalari. Bank tizimidan tortib SYNAPSE kabi platformagacha barchasi bu tushunchalardan foydalanadi.

**Tranzaksiya nima?**
Tranzaksiya — bir butun sifatida bajariladigan SQL buyruqlar to'plami. Yoki hammasi bajariladi, yoki hech biri.

**Bank misoli:**
```sql
-- Ali 1000 so'm o'tkazmoqchi Valiga
BEGIN;
    UPDATE accounts SET balance = balance - 1000 WHERE user_id = 1;  -- Alidan ayirish
    UPDATE accounts SET balance = balance + 1000 WHERE user_id = 2;  -- Valiga qo'shish
COMMIT;  -- Ikkalasi ham muvaffaqiyatli bo'lsa tasdiqlash

-- Agar biror xato bo'lsa:
ROLLBACK;  -- Ikkalasini ham bekor qilish
```

**SAVEPOINT — qisman bekor qilish:**
```sql
BEGIN;
    INSERT INTO orders (user_id, amount) VALUES (1, 500);
    SAVEPOINT order_created;

    INSERT INTO payments (order_id, status) VALUES (1, 'pending');
    -- Agar payment xato bo'lsa:
    ROLLBACK TO SAVEPOINT order_created;  -- Faqat payment bekor
    -- Order saqlanib qoladi
COMMIT;
```

**ACID tamoyillari:**
```
A — Atomicity    : Hammasi yoki hech narsa
C — Consistency  : Ma'lumotlar izchil holatda qoladi  
I — Isolation    : Parallel tranzaksiyalar bir-biriga ta'sir qilmaydi
D — Durability   : COMMIT dan keyin hatto server o'chsa ham saqlanadi
```

**Isolation darajalari:**
```sql
-- READ COMMITTED (default PostgreSQL)
BEGIN TRANSACTION ISOLATION LEVEL READ COMMITTED;

-- REPEATABLE READ — bir tranzaksiya davomida bir xil natija
BEGIN TRANSACTION ISOLATION LEVEL REPEATABLE READ;

-- SERIALIZABLE — eng qattiq, parallel kabi ketma-ket
BEGIN TRANSACTION ISOLATION LEVEL SERIALIZABLE;
```

**Stored Procedure — PL/pgSQL:**
```sql
-- Funksiya yaratish
CREATE OR REPLACE FUNCTION add_xp(
    p_user_id   BIGINT,
    p_amount    INTEGER,
    p_reason    TEXT DEFAULT 'dars_tugatildi'
)
RETURNS INTEGER AS $$
DECLARE
    v_new_xp    INTEGER;
    v_old_xp    INTEGER;
BEGIN
    -- Hozirgi XP ni ol
    SELECT xp_points INTO v_old_xp
    FROM users WHERE id = p_user_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Foydalanuvchi topilmadi: %', p_user_id;
    END IF;

    -- XP yangilash
    UPDATE users
    SET 
        xp_points = xp_points + p_amount,
        updated_at = NOW()
    WHERE id = p_user_id
    RETURNING xp_points INTO v_new_xp;

    -- Log yozish
    INSERT INTO xp_logs (user_id, amount, reason, old_xp, new_xp)
    VALUES (p_user_id, p_amount, p_reason, v_old_xp, v_new_xp);

    RETURN v_new_xp;
END;
$$ LANGUAGE plpgsql;

-- Ishlatish:
SELECT add_xp(1, 50, 'modul_1_quiz');
-- Natija: 550 (yangi XP)
```

**Streak yangilash — murakkab procedure:**
```sql
CREATE OR REPLACE FUNCTION update_streak(p_user_id BIGINT)
RETURNS TABLE(streak INTEGER, bonus_xp INTEGER) AS $$
DECLARE
    v_last_login    TIMESTAMPTZ;
    v_current_streak INTEGER;
    v_bonus          INTEGER := 0;
BEGIN
    SELECT last_login, streak_days 
    INTO v_last_login, v_current_streak
    FROM users WHERE id = p_user_id;

    IF v_last_login::DATE = CURRENT_DATE THEN
        -- Bugun allaqachon kirgan
        RETURN QUERY SELECT v_current_streak, 0;
        RETURN;
    ELSIF v_last_login::DATE = CURRENT_DATE - 1 THEN
        -- Kecha kirgan — streak davom etadi
        v_current_streak := v_current_streak + 1;
    ELSE
        -- Streak buzildi
        v_current_streak := 1;
    END IF;

    -- Milestone bonus
    IF v_current_streak IN (7, 30, 100) THEN
        v_bonus := v_current_streak * 10;
        PERFORM add_xp(p_user_id, v_bonus, 'streak_milestone');
    END IF;

    UPDATE users SET
        streak_days = v_current_streak,
        last_login = NOW()
    WHERE id = p_user_id;

    RETURN QUERY SELECT v_current_streak, v_bonus;
END;
$$ LANGUAGE plpgsql;

-- Ishlatish:
SELECT * FROM update_streak(1);
```

**Trigger — avtomatik bajarish:**
```sql
-- updated_at ni avtomatik yangilash
CREATE OR REPLACE FUNCTION set_updated_at()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trigger_users_updated_at
    BEFORE UPDATE ON users
    FOR EACH ROW
    EXECUTE FUNCTION set_updated_at();

-- Endi har UPDATE da updated_at avtomatik yangilanadi
UPDATE users SET xp_points = 100 WHERE id = 1;
-- updated_at avtomatik o'zgaradi!
```

**Real SYNAPSE tranzaksiya:**
```sql
-- Foydalanuvchini o'chirish (cascade manual)
CREATE OR REPLACE FUNCTION delete_user_cascade(p_user_id BIGINT)
RETURNS BOOLEAN AS $$
BEGIN
    -- Barcha bog'liq ma'lumotlarni o'chir
    DELETE FROM xp_logs WHERE user_id = p_user_id;
    DELETE FROM lesson_completions WHERE user_id = p_user_id;
    DELETE FROM support_tickets WHERE user_id = p_user_id;
    DELETE FROM enrollments WHERE user_id = p_user_id;
    DELETE FROM users WHERE id = p_user_id;

    IF NOT FOUND THEN
        RETURN FALSE;
    END IF;
    RETURN TRUE;

EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'Xato: %', SQLERRM;
    RETURN FALSE;
END;
$$ LANGUAGE plpgsql;

-- Ishlatish (tranzaksiya ichida):
BEGIN;
SELECT delete_user_cascade(5);
COMMIT;
```

