const express = require('express');
const { Pool } = require('pg');
const app = express();
app.use(express.json());

const pool = new Pool({ host:'localhost', database:'mydb', user:'postgres', password:'parol', max:10 });

app.get('/products', async (req, res) => {
  try {
    const { rows } = await pool.query('SELECT * FROM products ORDER BY id');
    res.json(rows);
  } catch (e) { res.status(500).json({ error: e.message }); }
});

app.post('/products', async (req, res) => {
  const { nom, narx, soni } = req.body;
  try {
    const { rows } = await pool.query(
      'INSERT INTO products (nom, narx, soni) VALUES ($1,$2,$3) RETURNING *',
      [nom, narx, soni]
    );
    res.status(201).json(rows[0]);
  } catch (e) { res.status(500).json({ error: e.message }); }
});

app.get('/products/:id', async (req, res) => {
  const { rows } = await pool.query('SELECT * FROM products WHERE id=$1', [req.params.id]);
  if (!rows[0]) return res.status(404).json({ error: 'Topilmadi' });
  res.json(rows[0]);
});

app.delete('/products/:id', async (req, res) => {
  const r = await pool.query('DELETE FROM products WHERE id=$1', [req.params.id]);
  res.json({ deleted: r.rowCount });
});

app.listen(3000, () => console.log('OK'));

