nazariya:
Mongoose — bu Node.js uchun MongoDB ODM (Object Document Mapper) kutubxonasi. U MongoDB ni obyektga asoslangan tarzda ishlatish imkonini beradi, schema va validatsiya qo'shadi.

## O'rnatish
```bash
npm install mongoose
```

## Ulanish
```javascript
const mongoose = require('mongoose');

async function connectDB() {
  try {
    await mongoose.connect('mongodb://localhost:27017/synapse_db');
    console.log('MongoDB ulandi!');
  } catch (err) {
    console.error('Ulanish xatosi:', err);
    process.exit(1);
  }
}

connectDB();

// Railway / Atlas uchun:
mongoose.connect(process.env.MONGODB_URI);
```

## Schema yaratish
```javascript
const { Schema, model } = require('mongoose');

const userSchema = new Schema({
  name: {
    type: String,
    required: [true, 'Ism majburiy'],
    trim: true,
    minlength: 2,
    maxlength: 50
  },
  email: {
    type: String,
    required: true,
    unique: true,
    lowercase: true,
    match: [/^\S+@\S+\.\S+$/, 'Email noto\'g\'ri']
  },
  age: {
    type: Number,
    min: [16, 'Yosh kamida 16 bo\'lishi kerak'],
    max: 100
  },
  course: {
    type: String,
    enum: ['Python', 'Web', 'Telegram Bot', 'TradingView', 'Data Analysis'],
    default: 'Python'
  },
  xp: { type: Number, default: 0 },
  isPremium: { type: Boolean, default: false },
  createdAt: { type: Date, default: Date.now }
}, {
  timestamps: true  // createdAt va updatedAt avtomatik
});

// Virtual field (saqlanmaydi, hisoblanadi)
userSchema.virtual('level').get(function() {
  return Math.floor(this.xp / 100);
});

// Instance method
userSchema.methods.addXP = function(amount) {
  this.xp += amount;
  return this.save();
};

// Static method
userSchema.statics.findByCourse = function(course) {
  return this.find({ course });
};

const User = model('User', userSchema);
module.exports = User;
```

## CRUD operatsiyalar (Mongoose)
```javascript
const User = require('./models/User');

// CREATE
const newUser = new User({ name: 'Ali', email: 'ali@gmail.com', course: 'Python' });
await newUser.save();

// Yoki:
await User.create({ name: 'Barno', email: 'barno@gmail.com' });

// READ
const users = await User.find({ course: 'Python' });
const user = await User.findById('64abc...');
const user2 = await User.findOne({ email: 'ali@gmail.com' });

// Chaining
const topUsers = await User
  .find({ xp: { $gt: 100 } })
  .select('name email xp')  // projection
  .sort({ xp: -1 })
