## MongoDB Transactions

Transaction — bu bir nechta operatsiyalar guruhini atomik tarzda bajarish. Ya'ni yoki hammasi bajariladi, yoki hech biri (all-or-nothing). MongoDB 4.0 versiyasidan multi-document transactions qo'llab-quvvatlanadi.

**Transaction qachon kerak:**
- Pul o'tkazish (bir accountdan olish + boshqasiga qo'shish)
- Buyurtma berish (inventory kamaytirish + order yaratish)
- Ko'p collectionda birgalikda o'zgarish

```javascript
const mongoose = require('mongoose');

async function transferXP(fromUserId, toUserId, amount) {
  // Session yaratish
  const session = await mongoose.startSession();

  try {
    // Transaction boshlash
    session.startTransaction();

    // 1. Yuboruvchidan XP ayirish
    const sender = await User.findByIdAndUpdate(
      fromUserId,
      { $inc: { xp: -amount } },
      { session, new: true }
    );

    // Tekshirish
    if (sender.xp < 0) {
      throw new Error('XP yetarli emas');
    }

    // 2. Qabul qiluvchiga XP qo'shish
    await User.findByIdAndUpdate(
      toUserId,
      { $inc: { xp: amount } },
      { session }
    );

    // 3. Transaction log yaratish
    await XPTransaction.create([{
      from: fromUserId,
      to: toUserId,
      amount,
      date: new Date()
    }], { session });

    // Hammasi muvaffaqiyatli — commit
    await session.commitTransaction();
    console.log('XP muvaffaqiyatli o\'tkazildi');

  } catch (error) {
    // Xato bo'ldi — rollback
    await session.abortTransaction();
    console.error('Transaction bekor qilindi:', error.message);
    throw error;
  } finally {
    // Session yopish
    session.endSession();
  }
}
```

