**Lua Scripting (atomic operatsiyalar):**
```javascript
// Atomik rate limiter
const rateLimitScript = `
  local key = KEYS[1]
  local limit = tonumber(ARGV[1])
  local window = tonumber(ARGV[2])

  local current = redis.call('INCR', key)
  if current == 1 then
    redis.call('EXPIRE', key, window)
  end

  if current > limit then
    return 0
  end
  return 1
`;

async function rateLimit(userId, limit = 100, window = 3600) {
  const key = `rate:${userId}:${Math.floor(Date.now() / 1000 / window)}`;
  const allowed = await redis.eval(rateLimitScript, 1, key, limit, window);
  return allowed === 1;
}
```

