-- =============================================
-- SYNAPSE Platform — To'liq Diplom Sxema
-- =============================================

CREATE EXTENSION IF NOT EXISTS pg_cron;

CREATE TABLE IF NOT EXISTS users (
  id         SERIAL PRIMARY KEY,
  email      VARCHAR(255) UNIQUE NOT NULL,
  full_name  VARCHAR(255) NOT NULL,
  xp         INT DEFAULT 0 CHECK (xp >= 0),
  direction  VARCHAR(50) CHECK (direction IN ('python','web','telegram','tradingview','data')),
  created_at TIMESTAMP DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS courses (
  id         SERIAL PRIMARY KEY,
  title      VARCHAR(255) NOT NULL,
  direction  VARCHAR(50) NOT NULL,
  weeks      INT DEFAULT 8,
  is_premium BOOLEAN DEFAULT FALSE
);

CREATE TABLE IF NOT EXISTS lessons (
  id         SERIAL PRIMARY KEY,
  course_id  INT REFERENCES courses(id) ON DELETE CASCADE,
  title      VARCHAR(255) NOT NULL,
  week_num   INT NOT NULL CHECK (week_num BETWEEN 1 AND 8),
  order_num  INT NOT NULL,
  xp_reward  INT DEFAULT 10
);

CREATE TABLE IF NOT EXISTS user_progress (
  user_id      INT REFERENCES users(id) ON DELETE CASCADE,
  lesson_id    INT REFERENCES lessons(id) ON DELETE CASCADE,
  score        NUMERIC(5,2) CHECK (score BETWEEN 0 AND 100),
  completed_at TIMESTAMP DEFAULT NOW(),
  PRIMARY KEY (user_id, lesson_id)
);

CREATE TABLE IF NOT EXISTS certificates (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id       INT REFERENCES users(id),
  course_id     INT REFERENCES courses(id),
  overall_score NUMERIC(5,2),
  issued_at     TIMESTAMP DEFAULT NOW(),
  UNIQUE (user_id, course_id)
);

CREATE TABLE IF NOT EXISTS leaderboard_cache (
  user_id    INT PRIMARY KEY REFERENCES users(id),
  xp         INT,
  rank_pos   INT,
  updated_at TIMESTAMP DEFAULT NOW()
);

-- INDEKSLAR
CREATE INDEX IF NOT EXISTS idx_progress_user    ON user_progress(user_id);
CREATE INDEX IF NOT EXISTS idx_progress_lesson  ON user_progress(lesson_id);
CREATE INDEX IF NOT EXISTS idx_lessons_course   ON lessons(course_id);
CREATE INDEX IF NOT EXISTS idx_users_direction  ON users(direction);
CREATE INDEX IF NOT EXISTS idx_users_xp         ON users(xp DESC);
CREATE INDEX IF NOT EXISTS idx_certs_user       ON certificates(user_id);

-- TRIGGER: Sertifikat avtomatik berish
CREATE OR REPLACE FUNCTION fn_auto_certificate()
RETURNS TRIGGER AS $$
DECLARE
  v_total    INT;
  v_done     INT;
  v_avg      NUMERIC;
  v_course   INT;
BEGIN
  SELECT l.course_id INTO v_course
  FROM lessons l WHERE l.id = NEW.lesson_id;

  SELECT COUNT(*) INTO v_total FROM lessons WHERE course_id = v_course;
  SELECT COUNT(*), AVG(score) INTO v_done, v_avg
  FROM user_progress up JOIN lessons l ON l.id = up.lesson_id
  WHERE up.user_id = NEW.user_id AND l.course_id = v_course;

  IF v_done >= v_total AND v_avg >= 70 THEN
    INSERT INTO certificates (user_id, course_id, overall_score)
    VALUES (NEW.user_id, v_course, v_avg)
    ON CONFLICT (user_id, course_id) DO NOTHING;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_auto_cert
AFTER INSERT ON user_progress
FOR EACH ROW EXECUTE FUNCTION fn_auto_certificate();

-- MATERIALIZED VIEW: Leaderboard
CREATE MATERIALIZED VIEW IF NOT EXISTS mv_leaderboard AS
SELECT
  u.id, u.full_name, u.direction, u.xp,
  RANK() OVER (ORDER BY u.xp DESC) AS rank_pos,
  COUNT(c.id) AS cert_count
FROM users u LEFT JOIN certificates c ON c.user_id = u.id
WHERE u.xp > 0
GROUP BY u.id, u.full_name, u.direction, u.xp;

CREATE UNIQUE INDEX IF NOT EXISTS uidx_leaderboard_user ON mv_leaderboard(id);

